+    pub curve: String,
+    /// Curve steepness for log/exp curves (1.0-20.0)
+    pub curve_steepness: f64,
+}
+
+impl Default for VolumeConfig {
+    fn default() -> Self {
+        Self {
+            step_min: 2,
