+            MediaKey::PrevTrack => 123, // Left arrow (with modifiers)
+            MediaKey::VolumeUp => 72,   // F11 equivalent
+            MediaKey::VolumeDown => 73, // F12 equivalent
+            MediaKey::Mute => 74,       // F10 equivalent
+        };
