+    }
+
+    fn get_default_output(&self) -> PlatformResult<AudioDevice> {
+        // TODO: Use CoreAudio to get the actual default device
+        Ok(AudioDevice {
+            id: "default".to_string(),
+            name: "Built-in Output".to_string(),
+            device_type: DeviceType::Speakers,
